mapper.update:
update memory_fact set status = #{status}, fact_content = #{factContent},
       decay_factor = #{decayFactor}, update_time = now()
where id = #{id}

update memory_fact
set decay_factor = case
    when event_time is null then 0.0
    else least(1.0, 1.0 - exp(-0.05 * greatest(0, datediff(now(), event_time))))
end,
update_time = now()
where user_id = #{userId}
  and status = 'ACTIVE'
  and fact_type = 'EVENT'
